/**
 * CAPADEX — additional concern question banks (seeded to `sdi_items`).
 *
 * WHY: the Simulation & Validation harness drives the real pipeline for 10 spec
 * personas, but several persona concerns had NO seeded question bank, so
 * `POST /api/capadex/session/start` returned 404 ("notSeeded") and those
 * personas were excluded from quality aggregates, dragging `concernCoverage`
 * below the 0.8 soft target.
 *
 * FIX (data, not code): author concern-specific banks for the previously
 * unseeded persona concerns and seed them through the SAME idempotent
 * `sdi_items` upsert used by the inline PRO/STUDENT banks in `routes/capadex.ts`.
 * Kept in this module (not inline) so `routes/capadex.ts` does not balloon.
 *
 * Convention (mirrors the inline banks):
 *  - 10 items × 4 stages (CAP_CUR / CAP_INS / CAP_GRW / CAP_MAS) per concern.
 *  - Curiosity (CAP_CUR) items are distress-worded `(-)` (a struggling persona
 *    agrees → high raw answer; the engine reverse-scores). A mix of `mcq`
 *    (4 options) and likert items, concept-token dense so the harness scores
 *    them on-topic.
 *  - Insight / Growth / Mastery items are growth-worded `(+)`.
 *  - `concern_name` matches the persona-library concern string EXACTLY so the
 *    `/start` concern_name lookup (tiers 2–3) resolves and the report's
 *    `concernName` round-trips for the harness concern-match check.
 */

export interface ConcernBankItem {
  item_code: string;
  question: string;
  weight: number;
  polarity: string;
  stage_code: string;
  concern_name: string;
  subdomain_code: string;
  question_type?: string;
  opt_a?: string;
  opt_b?: string;
  opt_c?: string;
  opt_d?: string;
}

